SELECT count(*) FROM company_name, movie_companies, title, kind_type, movie_info, info_type, cast_info, role_type, movie_keyword WHERE movie_companies.company_id = company_name.id AND movie_companies.movie_id = title.id AND title.kind_id = kind_type.id AND movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id AND cast_info.movie_id = title.id AND cast_info.role_id = role_type.id AND movie_keyword.movie_id = title.id;